import json
import os

class UserPreference:
    def __init__(self, preferences=None):
        self.preferences = preferences if preferences is not None else {}

    def save_to_file(self, file_path):
        with open(file_path, 'w') as f:
            json.dump(self.preferences, f)

    @staticmethod
    def load_from_file(file_path):
        if not os.path.exists(file_path):
            return UserPreference()
        with open(file_path, 'r') as f:
            data = json.load(f)
            return UserPreference(UserPreference.validate(data))

    @staticmethod
    def validate(data):
        if isinstance(data, dict):
            return {k: UserPreference.validate(v) for k, v in data.items()}
        elif isinstance(data, list):
            return [UserPreference.validate(item) for item in data]
        elif isinstance(data, (str, int, float, bool)):
            return data
        else:
            raise ValueError("Invalid data type in preferences")